// LOOKUP ANNEX C: dado el conjunto de 8 grupos con terceros, devuelve la asignación
// Returns: {P74:grp, P77:grp, P79:grp, P80:grp, P81:grp, P82:grp, P85:grp, P87:grp}
// donde grp es el grupo del 3ero que juega en ese partido

// Verificar si todos los 72 partidos de grupos tienen resultado

// FUNCIÓN PRINCIPAL: Calcular y cargar llaves de Dieciseisavos automáticamente
function generarLlavesDieciseisavos() {
  if (!allGroupsComplete()) {
    toast("Faltan resultados de la fase de grupos", true);
    return;
  }
  if (!confirm("¿Generar las llaves de Dieciseisavos automáticamente a partir de los resultados de grupos?")) return;

  const standings = calcGroupStandings();
  // Verificar que todos los grupos tengan al menos 3 equipos con partidos jugados
  const groups = ["A","B","C","D","E","F","G","H","I","J","K","L"];
  
  // Obtener 1eros y 2dos de cada grupo
  const firsts = {}, seconds = {}, thirds_all = [];
  groups.forEach(g => {
    const arr = standings[g] || [];
    if (arr.length >= 1) firsts[g] = arr[0].name;
    if (arr.length >= 2) seconds[g] = arr[1].name;
    if (arr.length >= 3) thirds_all.push({ ...arr[2], group: g });
  });

  // Obtener los 8 mejores terceros
  const best8thirds = [...thirds_all].sort((a,b) => {
    if (b.pts !== a.pts) return b.pts - a.pts;
    if (b.gd !== a.gd) return b.gd - a.gd;
    if (b.gf !== a.gf) return b.gf - a.gf;
    return 0;
  }).slice(0, 8);

  const third8groups = best8thirds.map(t => t.group);
  const thirdByGroup = {};
  best8thirds.forEach(t => { thirdByGroup[t.group] = t.name; });

  // Buscar en Annex C
  const allocation = annexCLookup(third8groups);
  
  // Partidos fijos (1ero vs 2do — siempre iguales):
  // P73: 2A vs 2B
  // P75: 1F vs 2C
  // P76: 1C vs 2F
  // P78: 2E vs 2I
  // P83: 2K vs 2L
  // P84: 1H vs 2J
  // P86: 1J vs 2H
  // P88: 2D vs 2G
  const fixed = {
    73: { h: seconds["A"], a: seconds["B"] },
    75: { h: firsts["F"],  a: seconds["C"] },
    76: { h: firsts["C"],  a: seconds["F"] },
    78: { h: seconds["E"], a: seconds["I"] },
    83: { h: seconds["K"], a: seconds["L"] },
    84: { h: firsts["H"],  a: seconds["J"] },
    86: { h: firsts["J"],  a: seconds["H"] },
    88: { h: seconds["D"], a: seconds["G"] },
  };

  // Partidos con 3eros (dependen de Annex C):
  // P74: 1E vs 3rd(allocation.P74)
  // P77: 1I vs 3rd(allocation.P77)
  // P79: 1A vs 3rd(allocation.P79)
  // P80: 1L vs 3rd(allocation.P80)
  // P81: 1D vs 3rd(allocation.P81)
  // P82: 1G vs 3rd(allocation.P82)
  // P85: 1B vs 3rd(allocation.P85)
  // P87: 1K vs 3rd(allocation.P87)
  const withThirds = {};
  if (allocation) {
    withThirds[74] = { h: firsts["E"], a: thirdByGroup[allocation.P74] || "?" };
    withThirds[77] = { h: firsts["I"], a: thirdByGroup[allocation.P77] || "?" };
    withThirds[79] = { h: firsts["A"], a: thirdByGroup[allocation.P79] || "?" };
    withThirds[80] = { h: firsts["L"], a: thirdByGroup[allocation.P80] || "?" };
    withThirds[81] = { h: firsts["D"], a: thirdByGroup[allocation.P81] || "?" };
    withThirds[82] = { h: firsts["G"], a: thirdByGroup[allocation.P82] || "?" };
    withThirds[85] = { h: firsts["B"], a: thirdByGroup[allocation.P85] || "?" };
    withThirds[87] = { h: firsts["K"], a: thirdByGroup[allocation.P87] || "?" };
  } else {
    // Si no encontramos en Annex C, asignar terceros en orden
    const thirdsArr = best8thirds.map(t => t.name);
    const midsWithThirds = [74,77,79,80,81,82,85,87];
    const winners = {74:firsts["E"],77:firsts["I"],79:firsts["A"],80:firsts["L"],81:firsts["D"],82:firsts["G"],85:firsts["B"],87:firsts["K"]};
    midsWithThirds.forEach((pid,i) => {
      withThirds[pid] = { h: winners[pid], a: thirdsArr[i] || "?" };
    });
  }

  // Guardar todos los equipos en S.elimTeams
  const allMatches = { ...fixed, ...withThirds };
  Object.entries(allMatches).forEach(([pid, teams]) => {
    S.elimTeams[Number(pid)] = { h: teams.h || "?", a: teams.a || "?" };
  });

  save();
  renderElim();
  renderBracket();
  renderRank();

  // Mostrar resumen
  const thirdsStr = best8thirds.map(t => `${t.group}: ${t.name} (${t.pts}pts)`).join(", ");
  const allNotFound = !allocation;
  toast(`✓ Llaves generadas${allNotFound ? " (Annex C no encontrado, orden estimado)" : ""}`);
  
  // Mostrar modal de resumen
  const summaryEl = document.getElementById("generate-summary");
  if (summaryEl) {
    summaryEl.innerHTML = `<div class="ib" style="margin-top:.5rem">
      <strong>Grupos clasificados:</strong><br>
      🥇 1eros: ${groups.map(g=>firsts[g]?g+": "+firsts[g]:"").filter(Boolean).join(", ")}<br>
      🥈 2dos: ${groups.map(g=>seconds[g]?g+": "+seconds[g]:"").filter(Boolean).join(", ")}<br>
      🥉 8 mejores 3eros: ${thirdsStr}<br>
      ${allocation ? "✅ Annex C aplicado" : "⚠️ Combinación no en tabla — asignación estimada"}
    </div>`;
    summaryEl.style.display = "block";
  }
}

function simularMarcadores(){
  // Find next incomplete phase
  let targetPhase=null;
  // First check group stage
  const gruposComplete=Array.from({length:72},(_,i)=>i+1).every(mid=>S.scores[mid]||S.scores[String(mid)]);
  if(!gruposComplete){
    if(!confirm("¿Simular marcadores de la Fase de Grupos? Solo llena los partidos vacíos."))return;
    for(let mid=1;mid<=72;mid++){
      if(S.scores[mid]||S.scores[String(mid)])continue;
      const h=Math.floor(Math.random()*4);
      const a=Math.floor(Math.random()*4);
      const v=validateScore(mid,h,a);
      if(v.ok){S.scores[mid]={h,a,live:false};S.checksums[mid]=makeChecksum(mid,h,a);}
    }
    save();renderFix();renderRank();updateGenerarBtn();
    toast("🎲 Fase de Grupos simulada");
    return;
  }
  // Then check each elim phase in order
  for(const phase of BONUS_PHASES){
    if(!phase.elimPhase)continue;
    const hasAny=phase.mids.some(pid=>S.elimScores[pid]||S.elimScores[String(pid)]);
    const allDone=phase.mids.every(pid=>S.elimScores[pid]||S.elimScores[String(pid)]);
    if(!allDone){targetPhase=phase;break;}
  }
  if(!targetPhase){toast("Todos los partidos ya tienen resultado",true);return;}
  if(!confirm(`¿Simular marcadores de ${targetPhase.label}? Solo llena los partidos vacíos.`))return;
  targetPhase.mids.forEach(pid=>{
    if(S.elimScores[pid]||S.elimScores[String(pid)])return;
    const teams=getRealElimTeams(pid);if(!teams)return;
    const h=Math.floor(Math.random()*4);
    const a=Math.floor(Math.random()*4);
    S.elimScores[pid]={h,a,live:false};
  });
  save();renderElim();renderBracket();renderRank();renderBonosPanel();
  toast(`🎲 ${targetPhase.label} simulada`);
}

// Actualizar estado del botón generar llaves según si grupos están completos
// Check if ANY elim phase needs prev phase closed before allowing results

function fetchESPNElimChecked(){
  const blocked=getFirstBlockedElimPhase();
  if(blocked){
    const prev=getPhaseByKey(blocked.prevPhase);
    toast(`🔒 Cierra "${prev?.label||blocked.prevPhase}" en Bonos antes de cargar resultados de ${blocked.label}`,true);
    return;
  }
  fetchESPNElim();
}

function simularMarcadoresChecked(){
  const blocked=getFirstBlockedElimPhase();
  if(blocked){
    const prev=getPhaseByKey(blocked.prevPhase);
    toast(`🔒 Cierra "${prev?.label||blocked.prevPhase}" en Bonos antes de simular ${blocked.label}`,true);
    return;
  }
  simularMarcadores();
}

// Update elim buttons disabled state based on blocked phases
function updateElimBtns(){
  const blocked=getFirstBlockedElimPhase();
  const espnBtn=document.getElementById("btn-espn-elim");
  const simBtn=document.getElementById("btn-simular");
  if(espnBtn){
    espnBtn.disabled=!!blocked;
    espnBtn.style.opacity=blocked?"0.45":"1";
    espnBtn.title=blocked?`Bloqueado: cierra ${getPhaseByKey(blocked?.prevPhase)?.label||""} primero`:"ESPN Live";
  }
  if(simBtn){
    simBtn.disabled=!!blocked;
    simBtn.style.opacity=blocked?"0.45":"1";
    simBtn.title=blocked?`Bloqueado: cierra ${getPhaseByKey(blocked?.prevPhase)?.label||""} primero`:"Simular marcadores";
  }
}

function updateGenerarBtn(){
  const btn=document.getElementById("btn-generar-llaves");
  const status=document.getElementById("generar-status");
  if(!btn)return;
  const played=Object.keys(S.scores).filter(m=>Number(m)>=1&&Number(m)<=72).length;
  const complete=played>=72;
  btn.disabled=!complete;
  btn.style.opacity=complete?"1":"0.45";
  if(status)status.textContent=complete?"✓ Fase de grupos completa":played+"/72 partidos";
}

// ══════════════════════════════════════════════════════════════
// ESPN — ELIMINATORIA (P73-P104)
// ══════════════════════════════════════════════════════════════
// Traducción de nombres ESPN (en) → español para los equipos
const ESPN_NAME_ES={
  "Mexico":"México","South Korea":"Corea del Sur","Czech Republic":"República Checa","Czechia":"República Checa",
  "Bosnia and Herzegovina":"Bosnia y Herzegovina","Qatar":"Catar","Switzerland":"Suiza",
  "Brazil":"Brasil","Morocco":"Marruecos","Haiti":"Haití","Scotland":"Escocia",
  "United States":"Estados Unidos","USA":"Estados Unidos","Turkey":"Turquía","Turkiye":"Turquía","Türkiye":"Turquía",
  "Germany":"Alemania","Ivory Coast":"Costa de Marfil","Cote d'Ivoire":"Costa de Marfil","Côte d'Ivoire":"Costa de Marfil","Ecuador":"Ecuador",
  "Netherlands":"Países Bajos","Japan":"Japón","Sweden":"Suecia","Tunisia":"Túnez",
  "Saudi Arabia":"Arabia Saudita","Uruguay":"Uruguay","Spain":"España","Cape Verde":"Cabo Verde",
  "Iran":"Irán","New Zealand":"Nueva Zelanda","Belgium":"Bélgica","Egypt":"Egipto",
  "France":"Francia","Senegal":"Senegal","Iraq":"Irak","Norway":"Noruega",
  "Argentina":"Argentina","Algeria":"Argelia","Austria":"Austria","Jordan":"Jordania",
  "Portugal":"Portugal","DR Congo":"RD Congo","Congo":"RD Congo","Uzbekistan":"Uzbekistán",
  "Colombia":"Colombia","England":"Inglaterra","Croatia":"Croacia","Ghana":"Ghana","Panama":"Panamá",
  "Paraguay":"Paraguay","Australia":"Australia","Korea Republic":"Corea del Sur","Curacao":"Curazao","Curaçao":"Curazao",
  "Canada":"Canadá","Bosnia-Herzegovina":"Bosnia y Herzegovina","South Africa":"Sudáfrica",
};

// Rango de fechas usado para consultar el scoreboard de ESPN — ya NO se
// usa para identificar el slot (eso es directo por ESPN_GAMEID_TO_PID, ver
// arriba), solo acota la ventana de la consulta.
const ELIM_DATES=["20260628","20260629","20260630","20260701","20260702","20260703","20260704","20260705","20260706","20260707","20260709","20260710","20260711","20260712","20260714","20260715","20260718","20260719"];

// Equipos "reales" conocidos hoy para un pid de eliminatoria, para poder
// comparar orientación/identidad contra lo que reporta ESPN. Para 1/16
// (73-88) viene de S.elimTeams; de Octavos en adelante viene de
// getRealElimTeams(), que resuelve recursivamente contra ELIM_TREE y los
// resultados de la fase previa (ya debería estar cerrada, ver
// getFirstBlockedElimPhase()).
function equiposConocidosElim(pid){
  if(ELIM_1_16_IDS.includes(pid))return(S.elimTeams[pid]&&S.elimTeams[pid].h)?S.elimTeams[pid]:null;
  return getRealElimTeams(pid);
}

async function fetchESPNElim(){
  const sp=document.getElementById("ei-spin");const tx=document.getElementById("ei-txt");
  if(sp)sp.classList.add("spin");if(tx)tx.textContent="Cargando...";
  setES(`<span style="color:var(--qb-muted);font-size:10px"><span class="spin" style="display:inline-block">↻</span> Consultando ESPN…</span>`);
  try{
    const results=await Promise.allSettled(ELIM_DATES.map(d=>fetch(`${ESPN_API}?dates=${d}&limit=50`).then(r=>r.ok?r.json():null).catch(()=>null)));
    const evts=[];
    results.forEach(r=>{if(r.status==="fulfilled"&&r.value?.events)r.value.events.forEach(ev=>evts.push(ev));});

    let updated=0,live=0,teamsLoaded=0,teamsCorrected=0;
    _elimConflictQueue=[];
    const pidsEnConflicto=new Set();

    evts.forEach(ev=>{
      // v7.0 — El partido se identifica por el gameId fijo de ESPN (ver
      // ESPN_GAMEID_TO_PID), no por nombre de equipo ni por orden
      // cronológico. Si el gameId no está en el mapa, no es uno de los 32
      // cruces de eliminatoria que rastreamos (es de fase de grupos).
      const pid=ESPN_GAMEID_TO_PID[String(ev.id)];
      if(!pid)return;

      const comp=ev.competitions?.[0]||{};const comps=comp.competitors||[];
      if(comps.length<2)return;
      const home=comps.find(c=>c.homeAway==="home")||comps[0];
      const away=comps.find(c=>c.homeAway==="away")||comps[1];
      const homeNameEN=home.team?.displayName||home.team?.shortDisplayName||"";
      const awayNameEN=away.team?.displayName||away.team?.shortDisplayName||"";
      const homeES=espnNameES(homeNameEN);
      const awayES=espnNameES(awayNameEN);
      const st=ev.status||comp.status;const state=st?.type?.state||"pre";

      if(ev.date&&!S.elimTimes[pid]){
        S.elimTimes[pid]=ev.date;
      }

      // ── Cruce real (solo aplica a 1/16, P73-P88 — las rondas
      //    posteriores se resuelven solas a partir de los resultados
      //    previos vía ELIM_TREE) ──
      if(ELIM_1_16_IDS.includes(pid)&&homeES&&awayES){
        const existT=S.elimTeams[pid];
        const sameTeams=!!(existT&&existT.h&&
          new Set([n(existT.h),n(existT.a)]).size===2&&
          [n(homeES),n(awayES)].every(x=>new Set([n(existT.h),n(existT.a)]).has(x)));
        if(!existT||!existT.h){
          // No había nada cargado para este cruce — lo cargamos directo.
          S.elimTeams[pid]={h:homeES,a:awayES};
          teamsLoaded++;
        }else if(!sameTeams){
          if(S.elimScores[pid]){
            // Ya hay un resultado guardado para este pid con OTROS
            // equipos — no lo pisamos en silencio, el admin decide.
            if(!pidsEnConflicto.has(pid)){
              _elimConflictQueue.push({pid,current:existT,espn:{h:homeES,a:awayES}});
              pidsEnConflicto.add(pid);
            }
          }else{
            // No hay resultado en juego todavía: corregir es seguro.
            S.elimTeams[pid]={h:homeES,a:awayES};
            teamsCorrected++;
          }
        }else if(n(existT.h)!==n(homeES)){
          // Mismos 2 equipos, pero local/visitante invertido respecto a lo
          // que reporta ESPN ahora — realinear no pierde información.
          S.elimTeams[pid]={h:homeES,a:awayES};
        }
      }

      if(pidsEnConflicto.has(pid))return; // llave pendiente de resolución, no tocar el marcador

      if(state==="post"||state==="in"){
        const hs=parseInt(home.score)||0;const as=parseInt(away.score)||0;
        const existing=S.elimScores[pid];
        // Orientación contra los equipos reales conocidos (1/16: recién
        // actualizado arriba; Octavos+: getRealElimTeams).
        const real=equiposConocidosElim(pid);
        let finalH=hs,finalA=as,orientable=true;
        if(real){
          if(n(real.h)===n(awayES)&&n(real.a)===n(homeES)){finalH=as;finalA=hs;}
          else if(!(n(real.h)===n(homeES)&&n(real.a)===n(awayES))){
            orientable=false; // ni coincide derecho ni invertido — no se adivina
          }
        }else if(!ELIM_1_16_IDS.includes(pid)){
          orientable=false; // fase previa todavía no resuelta/cerrada
        }
        if(orientable&&(!existing||existing.live)){
          S.elimScores[pid]={h:finalH,a:finalA,live:state==="in"};
          updated++;if(state==="in")live++;
        }
      }
    });

    save();
    const now=new Date().toLocaleTimeString("es",{hour:"2-digit",minute:"2-digit"});
    const lH=live>0?`<span class="sbadge" style="background:rgba(212,0,26,.18);color:#ff8080;border:1px solid rgba(212,0,26,.4)"><span class="ldot" style="width:5px;height:5px;margin-right:2px"></span>${live} en vivo</span>`:"";
    const tH=teamsLoaded>0?`<span class="sbadge info">🏴 ${teamsLoaded} equipos nuevos</span>`:"";
    const cH=teamsCorrected>0?`<span class="sbadge info">🔧 ${teamsCorrected} llave(s) corregida(s)</span>`:"";
    const wH=_elimConflictQueue.length>0?`<span class="sbadge warn">⚠️ ${_elimConflictQueue.length} conflicto(s) de llave</span>`:"";
    setES(`<span class="sbadge ok">✓ ESPN Elim · ${updated} resultados</span>${lH}${tH}${cH}${wH}<span style="color:var(--qb-muted)">${now}</span>`);
    if(_elimConflictQueue.length>0){
      const first=_elimConflictQueue.shift();
      openElimConflict(first.pid,first.current,first.espn);
    }else{
      renderElim();renderBracket();renderRank();autoFillRealityFromElim();
      toast(updated>0||teamsLoaded>0||teamsCorrected>0?`✓ ${updated} resultados · ${teamsLoaded} nuevos · ${teamsCorrected} corregidos`:"Sin datos nuevos");
    }
  }catch(e){setES(`<span class="sbadge err">⚠️ Error: ${e.message}</span>`);toast("Error ESPN",true);}
  if(sp)sp.classList.remove("spin");if(tx)tx.textContent="ESPN Live";
}

// ══════════════════════════════════════════════════════════════
// CONFLICTO DE LLAVE DE ELIMINATORIA — v7.0
// ══════════════════════════════════════════════════════════════
// Se dispara cuando ESPN confirma equipos DISTINTOS a los que ya están
// guardados en un pid que YA tiene un resultado cargado (manual o de una
// corrida anterior de ESPN/simulación) — pisarlo en silencio dejaría un
// marcador real pegado a los equipos equivocados. El admin decide.
function openElimConflict(pid,current,espn){
  const lbl=ELIM_1_16_LABELS[pid]||`P${pid}`;
  const sc=S.elimScores[pid]||{};
  document.getElementById("elim-conflict-body").innerHTML=
    `<strong>${lbl}</strong> ya tiene un resultado guardado (<strong>${sc.h}-${sc.a}</strong>) para estos equipos:<br><br>
     · Guardado ahora: <strong>${current.h} vs ${current.a}</strong><br>
     · ESPN confirma: <strong>${espn.h} vs ${espn.a}</strong><br><br>
     Si usás los equipos de ESPN, el resultado guardado se borra (ya no aplicaría a ese cruce) y vas a tener que volver a cargarlo.<br><br>
     ¿Qué querés conservar?`;
  _elimConflictCurrent={pid,current,espn};
  document.getElementById("elim-conflict-overlay").style.display="flex";
}
function resolveElimTeamConflict(choice){
  if(!_elimConflictCurrent)return;
  const{pid,espn}=_elimConflictCurrent;
  if(choice==="espn"){
    S.elimTeams[pid]={h:espn.h,a:espn.a};
    delete S.elimScores[pid];
    save();
  }
  _elimConflictCurrent=null;
  document.getElementById("elim-conflict-overlay").style.display="none";
  if(_elimConflictQueue.length>0){
    const next=_elimConflictQueue.shift();
    openElimConflict(next.pid,next.current,next.espn);
  }else{
    renderElim();renderBracket();renderRank();autoFillRealityFromElim();
    toast("✓ Conflictos de llave resueltos");
  }
}
function closeElimConflict(){resolveElimTeamConflict("keep");}

// ══════════════════════════════════════════════════════════════
// RENDER BRACKET — vista por participante
// ══════════════════════════════════════════════════════════════
// Get set of real teams that advanced FROM a given phase (winners of that phase's matches)

// For a given pid, what classified pts does predicting its winner earn?
// The classified pts come from the phase that CONTAINS this pid
// Example: pid 73 is in r16 phase → winner classified to Octavos → 3pts

function renderBracket(){
  const pidx=window._selB||0;window._selB=pidx;
  const sel=`<div style="display:flex;gap:5px;flex-wrap:wrap;margin-bottom:.75rem">${PL.map((name,i)=>{const m=PM[name]||{};return`<button onclick="window._selB=${i};renderBracket()" class="btn btn-sm ${i===pidx?"btn-blue":""}">${flagEmoji(m.champFlag,13)} ${sn(name)}</button>`;}).join("")}</div>`;
  document.getElementById("bsel").innerHTML=sel;
  const name=PL[pidx];if(!name){document.getElementById("bracket-body").innerHTML="";return;}

  // Resumen de puntos y llaves
  let llaveOk=0,llaveTot=0,totalPts=0,partJugados=0,cruceOk=0;
  for(let pid=73;pid<=104;pid++){
    const sc=S.elimScores[pid];if(!sc)continue;
    partJugados++;llaveTot++;
    if(isLlaveCorrecta(name,pid))llaveOk++;
    else if(findCruceValido(name,pid))cruceOk++;
    totalPts+=calcElimMatchPts(name,pid);
  }
  const advPts=calcAdv(name);
  const llavePtsTotal=(llaveOk+cruceOk)*2;

  // Classified pts for this participant
  let classifiedTotal=0;
  BONUS_PHASES.forEach(ph=>{if(ph.elimPhase)classifiedTotal+=calcClassifiedPtsForPhase(name,ph);});
  let html=`<div class="brkt-summary">
    <div class="bsum-item"><div class="bsum-val">${totalPts}</div><div class="bsum-lbl">pts resultado</div></div>
    <div class="bsum-item"><div class="bsum-val" style="color:#6ab8f7">${llavePtsTotal}</div><div class="bsum-lbl">pts llaves</div></div>
    <div class="bsum-item"><div class="bsum-val" style="color:#4dde8c">${classifiedTotal}</div><div class="bsum-lbl">pts clasif.</div></div>
    <div class="bsum-item"><div class="bsum-val">${llaveOk}/${llaveTot}${cruceOk?` <span style="color:#6ab8f7;font-size:10px">(+${cruceOk} 🔀)</span>`:""}</div><div class="bsum-lbl">llaves ✓</div></div>
    <div class="bsum-item"><div class="bsum-val">${partJugados}/32</div><div class="bsum-lbl">jugados</div></div>
  </div>`;

  // Leyenda
  html+=`<div style="display:flex;gap:8px;flex-wrap:wrap;font-size:10px;color:var(--qb-muted);margin-bottom:.625rem;padding:5px 9px;background:var(--qb-surface);border:1px solid var(--qb-border);border-radius:6px">
    <span><span style="display:inline-block;width:10px;height:10px;background:rgba(0,200,83,.1);border:1px solid rgba(0,200,83,.4);border-radius:2px;margin-right:3px"></span>Llave + resultado ✓</span>
    <span><span style="display:inline-block;width:10px;height:10px;background:rgba(245,166,35,.1);border:1px solid rgba(245,166,35,.4);border-radius:2px;margin-right:3px"></span>Llave ✓ resultado ✗</span>
    <span><span style="display:inline-block;width:10px;height:10px;background:rgba(106,184,247,.1);border:1px solid rgba(106,184,247,.4);border-radius:2px;margin-right:3px"></span>🔀 Cruce válido (mismo cruce, otra llave de la ronda)</span>
    <span><span style="display:inline-block;width:10px;height:10px;background:rgba(212,0,26,.1);border:1px solid rgba(212,0,26,.4);border-radius:2px;margin-right:3px"></span>Llave ✗</span>
    <span>⭐ = puntos de clasificado (en vivo, al cerrar la fase previa)</span>
  </div>`;

  ELIM_ROUNDS.forEach(round=>{
    html+=`<div class="brkt-round"><div class="brkt-round-title">${round.lbl}</div>`;
    round.ids.forEach(pid=>{
      // PREDICCIÓN del participante — siempre lo que ÉL puso
      const predTeams=getElimTeams(name,pid);   // equipos que el participante predijo
      const predScore=elimPred(name,pid);        // marcador que predijo

      // REALIDAD — lo que ocurrió realmente
      const realTeams=getRealElimTeams(pid);     // equipos reales del torneo
      const sc=S.elimScores[pid];                // resultado real

      const played=!!sc;
      const llave=isLlaveCorrecta(name,pid);
      const pts=calcElimMatchPts(name,pid);
      const cruce=!llave?findCruceValido(name,pid):null;
      const breakdown=calcElimMatchBreakdown(name,pid);

      // Equipos predichos (siempre se muestran)
      const pH=predTeams?predTeams.h:"⏳ Por resolver";
      const pA=predTeams?predTeams.a:"⏳ Por resolver";
      const pScoreStr=predScore?`${predScore.h}–${predScore.a}`:"?–?";

      // Equipos reales (solo si están cargados)
      const rH=realTeams?realTeams.h:null;
      const rA=realTeams?realTeams.a:null;
      const rScoreStr=sc?`${sc.h}–${sc.a}`:null;

      // Color de fondo según resultado
      let rowBg,borderCol;
      if(!played){
        rowBg="var(--qb-surface)";borderCol="var(--qb-border)";
      } else if(llave && pts>0){
        rowBg="rgba(0,200,83,.07)";borderCol="rgba(0,200,83,.4)";      // verde
      } else if(llave && pts===0){
        rowBg="rgba(245,166,35,.07)";borderCol="rgba(245,166,35,.4)";  // amarillo
      } else if(cruce && pts>0){
        rowBg="rgba(106,184,247,.08)";borderCol="rgba(106,184,247,.45)"; // azul = cruce válido
      } else {
        rowBg="rgba(212,0,26,.07)";borderCol="rgba(212,0,26,.4)";      // rojo
      }

      // Badge de estado
      let badge;
      if(!played && !realTeams){
        badge=`<span style="font-size:9px;color:var(--qb-muted)">⏳</span>`;
      } else if(!played && realTeams){
        badge=`<span style="font-size:9px;color:var(--qb-yellow)">📅 sin result.</span>`;
      } else if(cruce){
        const tip=`Cruce válido: ${pH} vs ${pA} se enfrentaron realmente en P${cruce.pidReal} (misma ronda). Se reconoce el acierto aunque no quedó en tu llave exacta.`.replace(/"/g,"&quot;");
        badge=`<span title="${tip}" style="font-size:9px;color:#6ab8f7;font-weight:700;cursor:help">🔀 Cruce ${pts>0?`+${pts}pts`:""}</span>`;
      } else if(!llave){
        badge=`<span style="font-size:9px;color:#ff8080;font-weight:600">✗ llave</span>`;
      } else if(pts>0){
        badge=`<span style="font-size:9px;color:#4dde8c;font-weight:700">+${pts}pts</span>`;
      } else {
        badge=`<span style="font-size:9px;color:var(--qb-yellow);font-weight:600">llave ✓</span>`;
      }

      // Bloque de comparación de equipos reales (si difieren de la predicción)
      let realBlock="";
      if(realTeams && (!predTeams || n(predTeams.h)!==n(realTeams.h) || n(predTeams.a)!==n(realTeams.a))){
        realBlock=`<div style="font-size:9px;color:var(--qb-muted);margin-top:2px;padding-top:2px;border-top:1px dashed var(--qb-border)">
          Real: <span style="color:var(--qb-text)">${rH}</span> vs <span style="color:var(--qb-text)">${rA}</span>
          ${rScoreStr?`· <strong style="color:var(--qb-text)">${rScoreStr}</strong>`:""}
        </div>`;
      } else if(realTeams && rScoreStr){
        realBlock=`<div style="font-size:9px;color:var(--qb-muted);margin-top:2px">Resultado real: <strong style="color:var(--qb-text)">${rScoreStr}</strong></div>`;
      }

      // Desglose de puntos: "2pts Llave + 2pts Ganador = +4pts" — usa
      // calcElimMatchBreakdown() como única fuente de verdad (mismos
      // items que suman el total ya mostrado en el badge).
      let breakdownBlock="";
      if(breakdown.length){
        const parts=breakdown.map(it=>`${it.pts}pts ${it.label}`).join(" + ");
        breakdownBlock=`<div style="font-size:9px;color:var(--qb-muted2);margin-top:2px">${parts} = <strong style="color:var(--qb-text)">+${pts}pts</strong></div>`;
      }

      // Option B: classified pts inline — predicted winner + did they advance?
      const clsBadge=getClassifiedBadgeForPid(name,pid);
      let clsBlock="";
      if(clsBadge){
        const nextRoundName={
          "r16":"Octavos","r8":"Cuartos","qf":"Semifinales","sf":"Final","final":"Campeón","third":"3er lugar"
        }[phaseForPid(pid)?.key]||"siguiente ronda";
        if(clsBadge.advanced){
          clsBlock=`<div style="display:flex;align-items:center;gap:5px;margin-top:5px;padding:4px 7px;background:rgba(0,200,83,.08);border:1px solid rgba(0,200,83,.3);border-radius:6px">
            <span style="font-size:13px">${clsBadge.flag}</span>
            <div style="flex:1;min-width:0">
              <span style="font-size:10px;font-weight:700;color:var(--qb-text)">${clsBadge.team}</span>
              <span style="font-size:9px;color:#4dde8c;margin-left:3px">clasificó a ${nextRoundName} ✓</span>
            </div>
            <span style="font-size:11px;font-weight:800;color:#4dde8c;white-space:nowrap">+${clsBadge.pts}pts</span>
          </div>`;
        }else{
          clsBlock=`<div style="display:flex;align-items:center;gap:5px;margin-top:5px;padding:4px 7px;background:rgba(212,0,26,.06);border:1px solid rgba(212,0,26,.2);border-radius:6px">
            <span style="font-size:13px">${clsBadge.flag}</span>
            <div style="flex:1;min-width:0">
              <span style="font-size:10px;font-weight:700;color:var(--qb-text)">${clsBadge.team}</span>
              <span style="font-size:9px;color:#ff8080;margin-left:3px">no clasificó ✗</span>
            </div>
            <span style="font-size:11px;font-weight:800;color:#ff8080;white-space:nowrap">0pts</span>
          </div>`;
        }
      }

      html+=`<div style="display:grid;grid-template-columns:1fr auto;align-items:start;gap:6px;padding:7px 9px;border:1px solid ${borderCol};border-radius:8px;margin-bottom:5px;background:${rowBg}">
        <div>
          <div style="display:flex;align-items:center;gap:5px;margin-bottom:1px">
            <span style="font-size:11px;font-weight:600;color:var(--qb-text)">${pH}</span>
            <span style="font-size:10px;color:var(--qb-muted)">vs</span>
            <span style="font-size:11px;font-weight:600;color:var(--qb-text)">${pA}</span>
          </div>
          <div style="font-size:10px;color:var(--qb-muted)">Predicción: <strong style="color:var(--qb-muted2)">${pScoreStr}</strong> · P${pid}</div>
          ${realBlock}
          ${breakdownBlock}
          ${clsBlock}
        </div>
        <div style="font-size:10px;color:var(--qb-muted);text-align:center;padding-top:2px">${badge}</div>
      </div>`;
    });
    html+="</div>";
  });

  document.getElementById("bracket-body").innerHTML=html;
}

function toggleHideParticipant(name){
  if(!S.hiddenPL)S.hiddenPL=new Set();
  if(!(S.hiddenPL instanceof Set))S.hiddenPL=new Set(Object.keys(S.hiddenPL).filter(k=>S.hiddenPL[k]));
  if(S.hiddenPL.has(name))S.hiddenPL.delete(name);
  else S.hiddenPL.add(name);
  save();renderRank();
}

// Posiciones previas para animar reordenamientos del ranking
const _prevRankPos={};

function renderRank(){
  // Revisar si hay fases nuevas cerradas antes de renderizar
  checkAndAwardBonos();
  const ranked=getRank();
  const played=Object.keys(S.scores).length;
  const elimPlayed=Object.keys(S.elimScores).length;
  document.getElementById("hstat").textContent=`${PL.length} participantes · ${played}/72 grupos · ${elimPlayed}/32 elim`;
  const masterBadge=document.getElementById("hdr-master-badge");
  if(masterBadge)masterBadge.textContent=`📂 Mi Quiniela · ${PL.length} participantes`;
  const rki=["🥇","🥈","🥉"];
  const tbody=document.getElementById("rb");

  // Snapshot de posiciones ANTES del redibujado (para saber qué filas subieron/bajaron)
  const prevPos={};
  Array.from(tbody.querySelectorAll("tr[data-rkey]")).forEach((tr,i)=>{
    prevPos[tr.dataset.rkey]=i;
  });

  tbody.innerHTML=ranked.map((p,i)=>{
    const rk=i<3?`<span style="font-size:20px">${rki[i]}</span>`:i===9?`<span style="font-size:20px">⚽</span>`:i===25?`<span style="font-size:20px">🚑</span>`:i===26?`<span style="font-size:20px">👸</span>`:`<span class="rk">${i+1}</span>`;
    const lnk=p.link?`<a href="${p.link}" target="_blank" class="lk">🔗</a>`:"—";
    const bonBadge=p.bon>0
      ?`<span class="pill" style="background:rgba(245,166,35,.15);color:#f5c842;border:1px solid rgba(245,166,35,.4)">${p.bon}</span>`
      :`<span style="color:var(--qb-muted);font-size:11px">—</span>`;
    const mv=getMovement(p.name,i+1);
    const admin=isAdmin();
    // Hidden participants show with reduced opacity in admin mode, hidden in spectator
    if(p.hidden&&!admin)return"";
    const hiddenStyle=p.hidden?"opacity:.4;":"";
    const adminActions=admin?`<td data-label="Hoja" style="display:flex;gap:3px;align-items:center">
      ${lnk}
      <button onclick="openEditParticipant('${p.name.replace(/'/g,"\'")}')" title="Editar" style="padding:2px 5px;font-size:10px;border:1px solid var(--qb-border2);border-radius:4px;background:var(--qb-surface2);color:var(--qb-muted);cursor:pointer">✏️</button>
      <button onclick="toggleHideParticipant('${p.name.replace(/'/g,"\'")}')" title="${p.hidden?"Mostrar":"Ocultar"}" style="padding:2px 5px;font-size:10px;border:1px solid var(--qb-border2);border-radius:4px;background:var(--qb-surface2);color:var(--qb-muted);cursor:pointer">${p.hidden?"👁":"🙈"}</button>
    </td>`:"";
    return`<tr data-rkey="${p.name}" style="${hiddenStyle}">
      <td data-label="#">${rk}</td>
      <td data-label="±" style="text-align:center">${mv}</td>
      <td data-label="País">${flagEmoji(p.champFlag,20)}</td>
      <td data-label="Participante"><div class="pn">${p.name}</div><div class="ps">${p.city||""}</div></td>
      <td data-label="Básicos"><span class="pill pb">${p.b}</span></td>
      <td data-label="Avanzado"><span class="pill pg">${p.av}</span></td>
      <td data-label="Elim"><span class="pill" style="background:rgba(124,58,237,.18);color:#c4b5fd;border:1px solid rgba(124,58,237,.35)">${p.elim}</span></td>
      <td data-label="Bonos">${bonBadge}</td>
      <td data-label="Total" style="text-align:right"><span class="ptb">${p.total}</span></td>
      ${adminActions}
    </tr>`;
  }).join("");

  // Animar solo las filas que cambiaron de posición respecto al render anterior
  Array.from(tbody.querySelectorAll("tr[data-rkey]")).forEach((tr,newIdx)=>{
    const key=tr.dataset.rkey;
    if(key in prevPos && prevPos[key]!==newIdx){
      const moved=newIdx<prevPos[key]?"rank-move-up":"rank-move-down";
      void tr.offsetWidth; // forzar reflow para reiniciar animación si ya tenía una
      tr.classList.add(moved);
      tr.addEventListener("animationend",()=>tr.classList.remove(moved),{once:true});
    }
  });

  if(typeof renderBattlesBanner==="function")renderBattlesBanner();
}

function renderFix(){
  const byG={};MIDS.forEach(mid=>{const g=MGMAP[mid]||"?";if(!byG[g])byG[g]=[];byG[g].push(mid);});
  const go=["A","B","C","D","E","F","G","H","I","J","K","L"];
  document.getElementById("fb").innerHTML=go.map(g=>{
    const mids=byG[g]||[];if(!mids.length)return"";
    return`<div class="gh"><span class="gl">Grupo ${g}</span></div>
    ${mids.map(mid=>{
      const m=MD[mid];if(!m)return"";
      const s=sc(mid);const played=!!s;const live=s?.live;
      const pts=m.lbl.split(" vs ");
      const hN=(pts[0]||"").trim();const aN=(pts[1]||"").trim();
      const hF=getFlag(g,hN);const aF=getFlag(g,aN);
      const mt=S.matchTimes[mid];
      let timeStr="";
      if(mt){
        const d=new Date(mt);
        const tz=Intl.DateTimeFormat().resolvedOptions().timeZone;
        timeStr=d.toLocaleTimeString("es",{hour:"2-digit",minute:"2-digit",timeZone:tz})+" · "+d.toLocaleDateString("es",{weekday:"short",day:"numeric",month:"short",timeZone:tz});
      }
      // Verificar checksum para mostrar indicador
      let checksumOk=true;
      if(s&&S.checksums[mid]){
        checksumOk=S.checksums[mid]===makeChecksum(mid,s.h,s.a);
      }
      const inpS="width:28px;text-align:center;font-size:13px;font-weight:700;padding:2px 3px;border-radius:4px;background:var(--qb-surface2);color:var(--qb-text);border:1px solid "+(played?(checksumOk?"var(--qb-green)":"var(--qb-yellow)"):"var(--qb-border2)");
      const rowS=live?"border:1px solid var(--qb-red);background:rgba(212,0,26,.07)":(!checksumOk?"border:1px solid var(--qb-yellow);background:rgba(245,166,35,.05)":"");
      return`<div class="mr" style="${rowS}">
        <div class="th"><span class="tn">${hN}</span><span style="font-size:14px">${hF}</span></div>
        <div style="display:flex;flex-direction:column;align-items:center;gap:2px">
          <div style="display:flex;align-items:center;gap:3px">
            <input type="text" inputmode="numeric" pattern="[0-9]*" maxlength="2" value="${s?s.h:""}" placeholder="-" onchange="onSC(${mid},'h',this.value)" style="${inpS}">
            <span style="font-size:11px;color:var(--qb-muted)">:</span>
            <input type="text" inputmode="numeric" pattern="[0-9]*" maxlength="2" value="${s?s.a:""}" placeholder="-" onchange="onSC(${mid},'a',this.value)" style="${inpS}">
          </div>
          <div class="sd">${live?`<span class="ldot"></span><span style="font-size:9px;color:#ef4444;font-weight:500">EN VIVO</span>`:`<span class="dot ${played?(checksumOk?"on":"warn"):""}"></span><span>P${mid}</span>`}${!checksumOk&&played?`<span style="font-size:9px;color:#f59e0b;font-weight:500">⚠</span>`:""}</div>
          ${timeStr&&!played?`<div style="font-size:8px;color:var(--qb-muted);text-align:center;white-space:nowrap">⏰ ${timeStr}</div>`:""}
          ${timeStr&&played?`<div style="font-size:8px;color:var(--qb-muted);text-align:center;white-space:nowrap">${timeStr}</div>`:""}
        </div>
        <div style="display:flex;align-items:center;gap:4px"><span style="font-size:14px">${aF}</span><span class="tn">${aN}</span></div>
      </div>`;
    }).join("")}`;
  }).join("");
}

const _pb={};
function onSC(mid,side,val){
  if(!_pb[mid])_pb[mid]={};
  _pb[mid][side]=val===""?null:parseInt(val);
  const cur=sc(mid)||{};
  const h=_pb[mid].h!==undefined?_pb[mid].h:(cur.h??null);
  const a=_pb[mid].a!==undefined?_pb[mid].a:(cur.a??null);
  if(h!==null&&a!==null){
    const ok=saveScore(mid,h,a,{live:cur.live||false});
    if(ok)toast("✓ Guardado");
  } else if(val===""){
    delete S.scores[mid];delete S.checksums[mid];delete _pb[mid];save();
  }
}

function resetFix(){if(!confirm("¿Borrar todos los resultados?"))return;S.scores={};S.checksums={};save();renderFix();renderRank();setFS("");toast("✓ Borrado");}
function setFS(html){const el=document.getElementById("fix-st");if(el)el.innerHTML=html;}

function exportFixJSON(){
  const blob=new Blob([JSON.stringify({v:"2.3",date:new Date().toISOString(),scores:S.scores,checksums:S.checksums,elimScores:S.elimScores,elimTeams:S.elimTeams},null,2)],{type:"application/json"});
  const url=URL.createObjectURL(blob);const a=document.createElement("a");
  a.href=url;a.download=`quiniela-${new Date().toISOString().slice(0,10)}.json`;a.click();URL.revokeObjectURL(url);toast("✓ JSON exportado");
}
function importFixJSON(input){
  const file=input.files[0];if(!file)return;
  const r=new FileReader();
  r.onload=e=>{
    try{
      const d=JSON.parse(e.target.result);const s=d.scores||d;let n=0,bad=0;
      Object.entries(s).forEach(([k,v])=>{
        if(v&&typeof v.h==="number"&&typeof v.a==="number"){
          const mid=Number(k)||k;
          const vr=validateScore(mid,v.h,v.a);
          if(vr.ok){S.scores[mid]=v;S.checksums[mid]=makeChecksum(mid,v.h,v.a);n++;}
          else bad++;
        }
      });
      save();renderFix();renderRank();
      setFS(`<span class="sbadge ok">✓ ${n} importados${bad?` · ${bad} rechazados por validación`:""}</span>`);
      toast(`✓ ${n} importados`);
    }catch(e2){toast("Error JSON",true);}
    input.value="";
  };r.readAsText(file);
}

// ══════════════════════════════════════════════════════════════
// ESPN — con protección de conflictos
// ══════════════════════════════════════════════════════════════
const ESPN_API="https://site.api.espn.com/apis/site/v2/sports/soccer/fifa.world/scoreboard";
const ALL_DATES=["20260611","20260612","20260613","20260614","20260615","20260616","20260617","20260618","20260619","20260620","20260621","20260622","20260623","20260624","20260625","20260626","20260627"];

async function fetchAllDates(dates){
  const results=await Promise.allSettled(dates.map(d=>fetch(`${ESPN_API}?dates=${d}&limit=50`).then(r=>r.ok?r.json():null).catch(()=>null)));
  const evts=[];
  results.forEach(r=>{if(r.status==="fulfilled"&&r.value?.events)r.value.events.forEach(ev=>evts.push(ev));});
  return evts;
}

// Cola de conflictos
function openConflict(mid,manual,espn,callback){
  const m=MD[mid];const lbl=m?.lbl||`Partido ${mid}`;
  document.getElementById("conflict-body").innerHTML=
    `<strong>${lbl}</strong><br><br>
     · Resultado manual guardado: <strong>${manual.h}-${manual.a}</strong><br>
     · ESPN trae ahora: <strong>${espn.h}-${espn.a}</strong><br><br>
     ¿Cuál quieres conservar?`;
  _conflictCurrent={mid,manual,espn,callback};
  document.getElementById("conflict-overlay").style.display="flex";
}
function resolveConflict(choice){
  if(!_conflictCurrent)return;
  const{mid,manual,espn,callback}=_conflictCurrent;
  if(choice==="espn"){saveScore(mid,espn.h,espn.a,{live:espn.live||false});}
  _conflictCurrent=null;
  document.getElementById("conflict-overlay").style.display="none";
  // Continuar con la cola
  if(_conflictQueue.length>0){const next=_conflictQueue.shift();openConflict(next.mid,next.manual,next.espn,next.callback);}
  else{renderFix();renderRank();toast("✓ Conflictos resueltos");}
}
function closeConflict(){resolveConflict("keep");}

async function fetchESPN(){
  const sp=document.getElementById("fi-spin");const tx=document.getElementById("fi-txt");
  if(sp)sp.classList.add("spin");if(tx)tx.textContent="Cargando...";
  setFS(`<span style="color:var(--qb-muted);font-size:10px"><span class="spin" style="display:inline-block">↻</span> Consultando ESPN…</span>`);
  try{
    const evts=await fetchAllDates(ALL_DATES);
    let updated=0,live=0,conflicts=0;
    _conflictQueue=[];
    evts.forEach(ev=>{
      const p=parseESPNEvent(ev);if(!p)return;
      // Always save match time if available
      if(ev.date&&!S.matchTimes[p.mid]){
        S.matchTimes[p.mid]=ev.date;
      }
      if(p.state==="post"||p.state==="in"){
        // CAPA 1: Validar resultado ESPN antes de procesar
        const vr=validateScore(p.mid,p.homeScore,p.awayScore);
        if(!vr.ok){console.warn(`ESPN P${p.mid} rechazado: ${vr.err}`);return;}
        const existing=sc(p.mid);
        if(existing&&!existing.live&&(existing.h!==p.homeScore||existing.a!==p.awayScore)&&p.state==="post"){
          // Hay conflicto: hay resultado manual y ESPN trae algo diferente
          conflicts++;
          _conflictQueue.push({mid:p.mid,manual:existing,espn:{h:p.homeScore,a:p.awayScore,live:false}});
        } else {
          // Sin conflicto: guardar directamente
          saveScore(p.mid,p.homeScore,p.awayScore,{live:p.state==="in"});
          updated++;if(p.state==="in")live++;
        }
      }
    });
    save();
    const now=new Date().toLocaleTimeString("es",{hour:"2-digit",minute:"2-digit"});
    const lH=live>0?`<span class="sbadge" style="background:rgba(212,0,26,.18);color:#ff8080;border:1px solid rgba(212,0,26,.4)"><span class="ldot" style="width:5px;height:5px;margin-right:2px"></span>${live} en vivo</span>`:"";
    const cH=conflicts>0?`<span class="sbadge warn">⚠️ ${conflicts} conflicto(s)</span>`:"";
    setFS(`<span class="sbadge ok">✓ ESPN · ${updated} resultados</span>${lH}${cH}<span style="color:var(--qb-muted)">${now}</span>`);
    if(conflicts>0){
      // Abrir primer conflicto de la cola
      const first=_conflictQueue.shift();
      openConflict(first.mid,first.manual,first.espn);
    } else {
      renderFix();renderRank();updateGenerarBtn();
      toast(updated>0?`✓ ${updated} resultados`:"Sin resultados nuevos");
    }
  }catch(e){setFS(`<span class="sbadge err">⚠️ Error: ${e.message}</span>`);toast("Error ESPN",true);}
  if(sp)sp.classList.remove("spin");if(tx)tx.textContent="ESPN Live";
}

function startMMT(){stopMMT();mmS=30;mmT=setInterval(()=>{mmS--;const el=document.getElementById("mm-cd");if(el)el.textContent=`Auto-actualiza en ${mmS}s`;if(mmS<=0){mmS=30;loadMM(false);}},1000);}
function stopMMT(){if(mmT){clearInterval(mmT);mmT=null;}}

async function loadMM(showSpinner=false){
  const sp=document.getElementById("mm-spin");const tx=document.getElementById("mm-txt");
  if(showSpinner){if(sp)sp.classList.add("spin");if(tx)tx.textContent="Cargando...";}
  const statusEl=document.getElementById("mm-status");
  try{
    const pad=n=>String(n).padStart(2,"0");const today=new Date();
    const d1=`${today.getFullYear()}${pad(today.getMonth()+1)}${pad(today.getDate())}`;
    const tmrw=new Date(today);tmrw.setDate(tmrw.getDate()+1);
    const d2=`${tmrw.getFullYear()}${pad(tmrw.getMonth()+1)}${pad(tmrw.getDate())}`;
    const evts=await fetchAllDates([d1,d2]);
    const now=new Date().toLocaleTimeString("es",{hour:"2-digit",minute:"2-digit"});
    const parsed=evts.map(ev=>({ev,p:parseESPNEvent(ev)})).filter(x=>x.p);
    const liveOnes=parsed.filter(x=>x.p.state==="in");
    const preOnes=parsed.filter(x=>x.p.state==="pre").sort((a,b)=>new Date(a.ev.date)-new Date(b.ev.date));
    if(statusEl)statusEl.innerHTML=`<span class="sbadge info">ESPN · ${now}</span>${liveOnes.length?`<span class="sbadge" style="background:rgba(212,0,26,.18);color:#ff8080;border:1px solid rgba(212,0,26,.4)"><span class="ldot" style="width:5px;height:5px;margin-right:2px"></span>${liveOnes.length} en vivo</span>`:""}`;
    renderMM(liveOnes,preOnes);
  }catch(e){if(statusEl)statusEl.innerHTML=`<span class="sbadge err">⚠️ Sin conexión ESPN</span>`;}
  if(showSpinner){if(sp)sp.classList.remove("spin");if(tx)tx.textContent="Actualizar";}
}

function predGroups(mid){const g={};PL.forEach(name=>{const p=MD[mid]?.preds[name];if(!p)return;const k=`${p.h}-${p.a}`;if(!g[k])g[k]=[];g[k].push(sn(name));});return g;}

function renderMM(liveList,preList){
  const body=document.getElementById("mm-body");if(!body)return;
  const showLive=liveList;const showNext=preList.slice(0,4);let html="";
  function buildCard(parsed,ev,isLive){
    const mid=parsed.mid;const g=MGMAP[mid]||"";const lbl=MD[mid]?.lbl||"";
    const pts=lbl.split(" vs ");const hN=(pts[0]||"").trim();const aN=(pts[1]||"").trim();
    const hF=getFlag(g,hN);const aF=getFlag(g,aN);
    const pgs=predGroups(mid);const sorted=Object.entries(pgs).sort((a,b)=>b[1].length-a[1].length);
    if(isLive){
      const hs=parsed.homeScore;const as=parsed.awayScore;const curKey=`${hs}-${as}`;
      const predsHtml=sorted.map(([score,names])=>{const hit=score===curKey;
        return`<div class="pred-row"><div class="pred-row-hdr"><span class="spill ${hit?"match":""}">${score.replace("-"," – ")}</span><span class="cpill">${names.length}</span>${hit?`<span style="font-size:10px;color:#15803d;font-weight:500">← actual</span>`:""}</div><div class="names">${names.map(n=>`<span class="nchip ${hit?"hit":""}">${n}</span>`).join("")}</div></div>`;
      }).join("")||`<div style="font-size:11px;color:var(--qb-muted);padding:4px 0">Sin predicciones</div>`;
      return`<div class="live-card is-live"><div class="live-hdr"><div style="display:flex;align-items:center;gap:6px"><span class="ldot"></span><span style="font-family:var(--ff-display);font-size:12px;font-weight:700;letter-spacing:.04em;color:var(--qb-red);text-transform:uppercase">EN VIVO</span>${parsed.clock?`<span style="font-size:11px;color:var(--qb-muted)">${parsed.clock}'</span>`:""}</div><span style="font-size:10px;color:var(--qb-muted)">Grupo ${g} · P${mid}</span></div><div class="scoreboard"><div class="live-team"><span class="live-team-flag">${hF}</span><span class="live-team-name">${hN}</span></div><div class="live-score red">${hs} – ${as}</div><div class="live-team"><span class="live-team-flag">${aF}</span><span class="live-team-name">${aN}</span></div></div><div style="padding:0 14px 6px;font-family:var(--ff-display);font-size:10px;font-weight:700;letter-spacing:.06em;color:var(--qb-muted);text-transform:uppercase">Predicciones de los 27</div><div class="pred-section">${predsHtml}</div></div>`;
    }else{
      const ko=new Date(ev.date).toLocaleTimeString("es",{hour:"2-digit",minute:"2-digit"});
      const koDate=new Date(ev.date).toLocaleDateString("es",{weekday:"short",day:"numeric",month:"short"});
      const predsHtml=sorted.map(([score,names])=>`<div class="pred-row"><div class="pred-row-hdr"><span class="spill">${score.replace("-"," – ")}</span><span class="cpill">${names.length}</span></div><div class="names">${names.map(n=>`<span class="nchip">${n}</span>`).join("")}</div></div>`).join("");
      return`<div class="live-card"><div class="live-hdr"><span style="font-family:var(--ff-display);font-size:12px;font-weight:700;letter-spacing:.03em;color:var(--qb-text)">Grupo ${g} · ${lbl}</span><span style="font-size:11px;color:var(--qb-muted)">⏱ ${ko} · ${koDate}</span></div><div class="scoreboard" style="padding:13px 14px 8px"><div class="live-team"><span class="live-team-flag">${hF}</span><span class="live-team-name">${hN}</span></div><div class="live-score" style="font-family:var(--ff-display);font-size:28px;font-weight:900;color:var(--qb-muted)">VS</div><div class="live-team"><span class="live-team-flag">${aF}</span><span class="live-team-name">${aN}</span></div></div>${predsHtml?`<div style="padding:0 14px 6px;font-family:var(--ff-display);font-size:10px;font-weight:700;letter-spacing:.06em;color:var(--qb-muted);text-transform:uppercase">Predicciones</div><div class="pred-section">${predsHtml}</div>`:""}</div>`;
    }
  }
  showLive.forEach(({ev,p})=>{html+=buildCard(p,ev,true);});
  if(showNext.length){if(showLive.length)html+=`<div style="font-family:var(--ff-display);font-size:10px;font-weight:700;letter-spacing:.07em;color:var(--qb-muted);text-transform:uppercase;margin:4px 0 8px">Próximos</div>`;showNext.forEach(({ev,p})=>{html+=buildCard(p,ev,false);});}
  if(!showLive.length&&!showNext.length){html=`<div class="mm-empty"><div style="font-size:32px;margin-bottom:.5rem">⚽</div><div style="font-family:var(--ff-display);font-size:16px;font-weight:700;letter-spacing:.03em;color:var(--qb-text);margin-bottom:.5rem">No hay partidos ahora mismo</div><div>Cuando empiece un partido aparecerá aquí con predicciones de los 27.</div><div style="margin-top:.75rem;font-size:10px;color:var(--qb-muted)">Auto-actualiza cada 30 segundos</div></div>`;}
  body.innerHTML=html;
}

